   415→  mobile: 768,
   416→  tablet: 1024,
   417→  laptop: 1440,
   418→  desktop: 1920,
   419→} as const;
   420→
   421→/**
   422→ * Grid configuration per breakpoint
   423→ */
   424→export const GRID_CONFIG = {
   425→  mobile: { columns: 4, gutter: 16, margin: 16 },
   426→  tablet: { columns: 8, gutter: 20, margin: 24 },
   427→  laptop: { columns: 12, gutter: 24, margin: 32 },
   428→  desktop: { columns: 12, gutter: 24, margin: 48 },
   429→} as const;
   430→
   431→// ============================================================================
   432→// Helper Functions
   433→// ============================================================================
   434→
   435→/**
   436→ * Determine KPI state based on value and thresholds
   437→ */
   438→export function getKPIState(
   439→  value: number,
   440→  warningThreshold: number,
   441→  criticalThreshold: number,
   442→  invertThresholds = false
   443→): KPIState {
   444→  if (invertThresholds) {
   445→    // Lower is worse (e.g., availability)
   446→    if (value < criticalThreshold) return 'critical';
   447→    if (value < warningThreshold) return 'warning';
   448→    return 'good';
   449→  } else {
   450→    // Higher is worse (e.g., cost variance)
   451→    if (Math.abs(value) > criticalThreshold) return 'critical';
   452→    if (Math.abs(value) > warningThreshold) return 'warning';
   453→    return 'good';
   454→  }
   455→}
   456→
   457→/**
   458→ * Format KPI value for display
   459→ */
   460→export function formatKPIValue(value: number, unit: KPICardData['unit']): string {
   461→  switch (unit) {
   462→    case '%':
   463→      return `${value.toFixed(1)}%`;
   464→    case 'km':
   465→      if (value >= 1000000) return `${(value / 1000000).toFixed(1)}M km`;
   466→      if (value >= 1000) return `${(value / 1000).toFixed(1)}K km`;
   467→      return `${value.toFixed(0)} km`;
   468→    case 'trains':
   469→      return `${value}`;
   470→    case 'hours':
   471→      return `${value.toFixed(0)}h`;
   472→    case 'currency':
   473→      if (Math.abs(value) >= 1000000) return `$${(value / 1000000).toFixed(1)}M`;
   474→      if (Math.abs(value) >= 1000) return `$${(value / 1000).toFixed(1)}K`;
   475→      return `$${value.toFixed(0)}`;
   476→    default:
   477→      return String(value);
   478→  }
   479→}
   480→
   481→/**
   482→ * Get trend direction from value change
   483→ */
   484→export function getTrendDirection(current: number, previous: number): TrendDirection {
   485→  const diff = current - previous;
   486→  if (Math.abs(diff) < 0.001) return 'stable';
   487→  return diff > 0 ? 'up' : 'down';
   488→}
   489→
   490→/**
   491→ * Calculate fleet status distribution percentages
   492→ */
   493→export function calculateStatusPercentages(summary: FleetStatusSummary): {
   494→  fit: number;
   495→  inMaintenance: number;
   496→  outOfService: number;
   497→  restricted: number;
   498→} {
   499→  const total = summary.totalTrains;
   500→  if (total === 0) {
   501→    return { fit: 0, inMaintenance: 0, outOfService: 0, restricted: 0 };
   502→  }
   503→
   504→  return {
   505→    fit: (summary.statusDistribution.fit / total) * 100,
   506→    inMaintenance: (summary.statusDistribution.inMaintenance / total) * 100,
   507→    outOfService: (summary.statusDistribution.outOfService / total) * 100,
   508→    restricted: (summary.statusDistribution.restricted / total) * 100,
   509→  };
   510→}
   511→
   512→/**
   513→ * Get default widget configuration for a role
