   518→    { id: 'alerts', title: 'Alerts & Warnings', enabled: true, position: { row: 2, col: 6 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 30000 },
   519→  ];
   520→
   521→  switch (role) {
   522→    case 'fleet_manager':
