   524→        ...baseWidgets,
   525→        { id: 'fleet_status', title: 'Fleet Status', enabled: true, position: { row: 2, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 60000 },
   526→        { id: 'pm_timeline', title: 'PM Schedule', enabled: true, position: { row: 6, col: 0 }, size: { width: 12, height: 3 }, collapsed: false, refreshInterval: 300000 },
   527→        { id: 'cost_compliance', title: 'Cost Compliance', enabled: true, position: { row: 9, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 3600000 },
   528→      ];
   529→
   530→    case 'maintenance_planner':
   531→      return [
   532→        ...baseWidgets,
   533→        { id: 'pm_timeline', title: 'PM Schedule', enabled: true, position: { row: 2, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 300000 },
   534→        { id: 'resource_chart', title: 'Resource Utilisation', enabled: true, position: { row: 6, col: 0 }, size: { width: 12, height: 4 }, collapsed: false, refreshInterval: 300000 },
   535→        { id: 'mileage_variance', title: 'Mileage Variance', enabled: true, position: { row: 10, col: 0 }, size: { width: 6, height: 3 }, collapsed: false, refreshInterval: 300000 },
   536→      ];
   537→
   538→    case 'operations_manager':
   539→      return [
   540→        ...baseWidgets,
   541→        { id: 'run_assignments', title: "Today's Assignments", enabled: true, position: { row: 2, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 60000 },
   542→        { id: 'fleet_status', title: 'Fleet Status', enabled: true, position: { row: 6, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 60000 },
   543→        { id: 'mileage_variance', title: 'Mileage Balance', enabled: true, position: { row: 6, col: 6 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 300000 },
   544→      ];
   545→
