/**
 * Mobile Responsive UI Types
 *
 * TypeScript types for mobile-responsive design patterns.
 * Based on UX specification MILEAGE-UX-010.
 */

import type { FleetType, Train, TrainStatus, FitnessStatus, PMLevel } from './train';
import type { AlertPriority } from './notification-ui';

// ============================================================================
// Breakpoint Types
// ============================================================================

/**
 * Responsive breakpoint names
 */
export type Breakpoint = 'xs' | 'sm' | 'md' | 'lg' | 'xl' | 'xxl';

/**
 * Breakpoint configuration
 */
export interface BreakpointConfig {
  name: Breakpoint;
  minWidth: number;
  maxWidth: number | null;
  columns: number;
  containerPadding: number;
  gutterWidth: number;
}

/**
 * Breakpoint definitions
 */
export const BREAKPOINTS: Record<Breakpoint, Omit<BreakpointConfig, 'name'>> = {
  xs: { minWidth: 0, maxWidth: 575, columns: 1, containerPadding: 16, gutterWidth: 16 },
  sm: { minWidth: 576, maxWidth: 767, columns: 1, containerPadding: 16, gutterWidth: 16 },
  md: { minWidth: 768, maxWidth: 991, columns: 2, containerPadding: 24, gutterWidth: 24 },
  lg: { minWidth: 992, maxWidth: 1199, columns: 3, containerPadding: 24, gutterWidth: 24 },
  xl: { minWidth: 1200, maxWidth: 1399, columns: 4, containerPadding: 32, gutterWidth: 32 },
  xxl: { minWidth: 1400, maxWidth: null, columns: 4, containerPadding: 32, gutterWidth: 32 },
};

/**
 * Device type based on breakpoint
 */
export type DeviceType = 'mobile' | 'tablet' | 'desktop';

// ============================================================================
// Navigation Types
// ============================================================================

/**
 * Navigation item
 */
export interface NavigationItem {
  id: string;
  label: string;
  icon: string;
  route: string;
  badge?: number | string;
  roles?: string[];
  children?: NavigationItem[];
}

/**
 * Bottom tab bar item
 */
export interface BottomTabItem {
  id: string;
  label: string;
  icon: string;
  activeIcon: string;
  route: string;
  badge?: number | string;
}

/**
 * Mobile navigation state
 */
export interface MobileNavigationState {
  isMenuOpen: boolean;
  activeTab: string;
  activeRoute: string;
  breadcrumbs: Array<{ label: string; route: string }>;
}

/**
 * Default bottom tabs
 */
export const DEFAULT_BOTTOM_TABS: BottomTabItem[] = [
  { id: 'home', label: 'Home', icon: 'home-outline', activeIcon: 'home', route: '/' },
  { id: 'trains', label: 'Trains', icon: 'train-outline', activeIcon: 'train', route: '/trains' },
  { id: 'schedule', label: 'Schedule', icon: 'calendar-outline', activeIcon: 'calendar', route: '/schedule' },
  { id: 'alerts', label: 'Alerts', icon: 'bell-outline', activeIcon: 'bell', route: '/alerts' },
  { id: 'more', label: 'More', icon: 'menu', activeIcon: 'menu', route: '/more' },
];

// ============================================================================
// Card Types (Mobile Layout)
// ============================================================================

/**
 * Train card for mobile display
 */
export interface MobileTrainCard {
  trainId: string;
  trainName?: string;
  fleetType: FleetType;
  status: TrainStatus;
  fitnessStatus: FitnessStatus;
  currentMileage: number;
  pmWindowPercent: number;
  pmWindowStatus: 'SAFE' | 'APPROACHING' | 'CRITICAL' | 'OVERDUE';
  nextPM: {
    level: PMLevel;
    daysRemaining: number;
    milesRemaining: number;
  };
  todayRoute?: string;
  lastUpdated: Date;
  alertPriority?: AlertPriority;
}

/**
 * Task card for field worker view
 */
export interface MobileTaskCard {
  id: string;
  type: 'PM' | 'INSPECTION' | 'REPAIR' | 'OTHER';
  trainId: string;
  trainName?: string;
  title: string;
  description: string;
  priority: 'URGENT' | 'HIGH' | 'NORMAL' | 'LOW';
  track?: string;
  scheduledStart: Date;
  scheduledEnd: Date;
  status: 'PENDING' | 'IN_PROGRESS' | 'COMPLETED' | 'BLOCKED';
  estimatedDuration: number; // minutes
  assignedTo?: string;
}

/**
 * KPI card for mobile dashboard
 */
export interface MobileKPICard {
  id: string;
  label: string;
  value: number | string;
  unit?: string;
  trend?: 'UP' | 'DOWN' | 'NEUTRAL';
  trendValue?: number;
  status: 'GOOD' | 'WARNING' | 'CRITICAL';
  sparklineData?: number[];
}

// ============================================================================
// Bottom Sheet Types
// ============================================================================

/**
 * Bottom sheet height presets
 */
export type BottomSheetHeight = 'AUTO' | 'HALF' | 'FULL';

/**
 * Bottom sheet configuration
 */
export interface BottomSheetConfig {
  height: BottomSheetHeight;
  showDragHandle: boolean;
  dismissOnBackdrop: boolean;
  dismissOnSwipeDown: boolean;
  snapPoints?: number[]; // percentages
}

/**
 * Bottom sheet state
 */
export interface BottomSheetState {
  isOpen: boolean;
  currentHeight: number;
  contentId?: string;
  config: BottomSheetConfig;
}

/**
 * Default bottom sheet config
 */
export const DEFAULT_BOTTOM_SHEET_CONFIG: BottomSheetConfig = {
  height: 'AUTO',
  showDragHandle: true,
  dismissOnBackdrop: true,
  dismissOnSwipeDown: true,
  snapPoints: [25, 50, 90],
};

// ============================================================================
// Filter Types (Mobile)
// ============================================================================

/**
 * Mobile filter option
 */
export interface MobileFilterOption {
  id: string;
  label: string;
  value: string | number | boolean;
  count?: number;
  disabled?: boolean;
}

/**
 * Mobile filter group
 */
export interface MobileFilterGroup {
  id: string;
  label: string;
  type: 'RADIO' | 'CHECKBOX' | 'RANGE' | 'DATE';
  options: MobileFilterOption[];
  selectedValues: Array<string | number | boolean>;
}

/**
 * Mobile filter state
 */
export interface MobileFilterState {
  isOpen: boolean;
  groups: MobileFilterGroup[];
  appliedCount: number;
  resultCount?: number;
}

// ============================================================================
// Gesture Types
// ============================================================================

/**
 * Swipe direction
 */
export type SwipeDirection = 'LEFT' | 'RIGHT' | 'UP' | 'DOWN';

/**
 * Swipe action configuration
 */
export interface SwipeActionConfig {
  direction: SwipeDirection;
  threshold: number; // pixels to trigger
  icon: string;
  label: string;
  color: string;
  action: string; // action identifier
}

/**
 * List item swipe actions
 */
export interface ListItemSwipeActions {
  left?: SwipeActionConfig;
  right?: SwipeActionConfig;
}

/**
 * Pull to refresh state
 */
export interface PullToRefreshState {
  isRefreshing: boolean;
  pullDistance: number;
  threshold: number;
}

// ============================================================================
// Offline Types
// ============================================================================

/**
 * Network status
 */
export type NetworkStatus = 'ONLINE' | 'OFFLINE' | 'SLOW';

/**
 * Sync status
 */
export type SyncStatus = 'SYNCED' | 'PENDING' | 'SYNCING' | 'FAILED';

/**
 * Offline queue item
 */
export interface OfflineQueueItem {
  id: string;
  type: 'CREATE' | 'UPDATE' | 'DELETE';
  entity: string;
  data: Record<string, unknown>;
  createdAt: Date;
  attempts: number;
  lastAttempt?: Date;
  error?: string;
}

/**
 * Offline state
 */
export interface OfflineState {
  networkStatus: NetworkStatus;
  lastOnline?: Date;
  queuedItems: OfflineQueueItem[];
  pendingCount: number;
  failedCount: number;
}

/**
 * Cached data metadata
 */
export interface CacheMetadata {
  key: string;
  cachedAt: Date;
  expiresAt?: Date;
  stale: boolean;
  size: number; // bytes
}

// ============================================================================
// PWA Types
// ============================================================================

/**
 * PWA install state
 */
export interface PWAInstallState {
  isInstallable: boolean;
  isInstalled: boolean;
  isPromptDismissed: boolean;
  installPromptEvent?: Event;
}

/**
 * PWA update state
 */
export interface PWAUpdateState {
  isUpdateAvailable: boolean;
  isUpdating: boolean;
  lastChecked?: Date;
}

/**
 * Service worker registration state
 */
export interface ServiceWorkerState {
  isSupported: boolean;
  isRegistered: boolean;
  isActive: boolean;
  updateAvailable: boolean;
  error?: string;
}

// ============================================================================
// Touch Types
// ============================================================================

/**
 * Touch target specification
 */
export interface TouchTargetSpec {
  minWidth: number;
  minHeight: number;
  recommendedWidth: number;
  recommendedHeight: number;
}

/**
 * Touch targets by element type
 */
export const TOUCH_TARGETS: Record<string, TouchTargetSpec> = {
  button: { minWidth: 48, minHeight: 48, recommendedWidth: 56, recommendedHeight: 56 },
  listItem: { minWidth: 48, minHeight: 48, recommendedWidth: 56, recommendedHeight: 56 },
  input: { minWidth: 48, minHeight: 48, recommendedWidth: 56, recommendedHeight: 56 },
  tabItem: { minWidth: 48, minHeight: 48, recommendedWidth: 64, recommendedHeight: 64 },
  checkbox: { minWidth: 44, minHeight: 44, recommendedWidth: 44, recommendedHeight: 44 },
  radio: { minWidth: 44, minHeight: 44, recommendedWidth: 44, recommendedHeight: 44 },
  iconButton: { minWidth: 44, minHeight: 44, recommendedWidth: 48, recommendedHeight: 48 },
  fieldWorkerButton: { minWidth: 64, minHeight: 64, recommendedWidth: 72, recommendedHeight: 72 },
};

// ============================================================================
// Role-Based View Types
// ============================================================================

/**
 * Mobile role
 */
export type MobileRole = 'OPERATIONS' | 'MAINTENANCE' | 'MANAGEMENT';

/**
 * Role-specific bottom tabs
 */
export const ROLE_BOTTOM_TABS: Record<MobileRole, BottomTabItem[]> = {
  OPERATIONS: [
    { id: 'home', label: 'Home', icon: 'home-outline', activeIcon: 'home', route: '/' },
    { id: 'trains', label: 'Trains', icon: 'train-outline', activeIcon: 'train', route: '/trains' },
    { id: 'schedule', label: 'Schedule', icon: 'calendar-outline', activeIcon: 'calendar', route: '/schedule' },
    { id: 'alerts', label: 'Alerts', icon: 'bell-outline', activeIcon: 'bell', route: '/alerts' },
    { id: 'more', label: 'More', icon: 'menu', activeIcon: 'menu', route: '/more' },
  ],
  MAINTENANCE: [
    { id: 'home', label: 'Home', icon: 'home-outline', activeIcon: 'home', route: '/' },
    { id: 'tasks', label: 'Tasks', icon: 'clipboard-outline', activeIcon: 'clipboard', route: '/tasks' },
    { id: 'tools', label: 'Tools', icon: 'wrench-outline', activeIcon: 'wrench', route: '/tools' },
    { id: 'reports', label: 'Reports', icon: 'document-outline', activeIcon: 'document', route: '/reports' },
    { id: 'more', label: 'More', icon: 'menu', activeIcon: 'menu', route: '/more' },
  ],
  MANAGEMENT: [
    { id: 'home', label: 'Home', icon: 'home-outline', activeIcon: 'home', route: '/' },
    { id: 'kpis', label: 'KPIs', icon: 'analytics-outline', activeIcon: 'analytics', route: '/kpis' },
    { id: 'approvals', label: 'Approvals', icon: 'checkmark-circle-outline', activeIcon: 'checkmark-circle', route: '/approvals' },
    { id: 'reports', label: 'Reports', icon: 'document-outline', activeIcon: 'document', route: '/reports' },
    { id: 'more', label: 'More', icon: 'menu', activeIcon: 'menu', route: '/more' },
  ],
};

// ============================================================================
// Accessibility Types
// ============================================================================

/**
 * Accessibility preferences
 */
export interface AccessibilityPreferences {
  reduceMotion: boolean;
  highContrast: boolean;
  largeText: boolean;
  screenReader: boolean;
}

/**
 * Focus trap configuration
 */
export interface FocusTrapConfig {
  containerId: string;
  initialFocusId?: string;
  returnFocusId?: string;
  escapeDeactivates: boolean;
}

// ============================================================================
// Performance Types
// ============================================================================

/**
 * Performance metrics
 */
export interface PerformanceMetrics {
  fcp: number; // First Contentful Paint
  lcp: number; // Largest Contentful Paint
  tti: number; // Time to Interactive
  tbt: number; // Total Blocking Time
  cls: number; // Cumulative Layout Shift
}

/**
 * Performance budget
 */
export interface PerformanceBudget {
  fcp: number;
  lcp: number;
  tti: number;
  tbt: number;
  cls: number;
  bundleSize: number; // KB
}

/**
 * Default performance budgets
 */
export const PERFORMANCE_BUDGETS: Record<DeviceType, PerformanceBudget> = {
  mobile: { fcp: 3000, lcp: 4000, tti: 7000, tbt: 600, cls: 0.1, bundleSize: 200 },
  tablet: { fcp: 2000, lcp: 3000, tti: 5000, tbt: 400, cls: 0.1, bundleSize: 200 },
  desktop: { fcp: 1500, lcp: 2500, tti: 3500, tbt: 200, cls: 0.1, bundleSize: 200 },
};

// ============================================================================
// UI State Types
// ============================================================================

/**
 * Mobile app state
 */
export interface MobileAppState {
  currentBreakpoint: Breakpoint;
  deviceType: DeviceType;
  orientation: 'PORTRAIT' | 'LANDSCAPE';
  navigation: MobileNavigationState;
  offline: OfflineState;
  pwa: {
    install: PWAInstallState;
    update: PWAUpdateState;
    serviceWorker: ServiceWorkerState;
  };
  accessibility: AccessibilityPreferences;
  bottomSheet: BottomSheetState;
  pullToRefresh: PullToRefreshState;
}

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Get current breakpoint from window width
 */
export function getCurrentBreakpoint(width: number): Breakpoint {
  if (width < 576) return 'xs';
  if (width < 768) return 'sm';
  if (width < 992) return 'md';
  if (width < 1200) return 'lg';
  if (width < 1400) return 'xl';
  return 'xxl';
}

/**
 * Get device type from breakpoint
 */
export function getDeviceType(breakpoint: Breakpoint): DeviceType {
  if (breakpoint === 'xs' || breakpoint === 'sm') return 'mobile';
  if (breakpoint === 'md' || breakpoint === 'lg') return 'tablet';
  return 'desktop';
}

/**
 * Check if mobile breakpoint
 */
export function isMobile(breakpoint: Breakpoint): boolean {
  return breakpoint === 'xs' || breakpoint === 'sm';
}

/**
 * Check if tablet breakpoint
 */
export function isTablet(breakpoint: Breakpoint): boolean {
  return breakpoint === 'md' || breakpoint === 'lg';
}

/**
 * Check if desktop breakpoint
 */
export function isDesktop(breakpoint: Breakpoint): boolean {
  return breakpoint === 'xl' || breakpoint === 'xxl';
}

/**
 * Get bottom tabs for role
 */
export function getBottomTabsForRole(role: MobileRole): BottomTabItem[] {
  return ROLE_BOTTOM_TABS[role];
}

/**
 * Format mileage for mobile display
 */
export function formatMileageMobile(mileage: number): string {
  if (mileage >= 1000) {
    return `${(mileage / 1000).toFixed(1)}k`;
  }
  return mileage.toString();
}

/**
 * Get PM window status color
 */
export function getPMWindowStatusColor(status: MobileTrainCard['pmWindowStatus']): string {
  const colors: Record<MobileTrainCard['pmWindowStatus'], string> = {
    SAFE: '#22C55E',
    APPROACHING: '#F59E0B',
    CRITICAL: '#EF4444',
    OVERDUE: '#DC2626',
  };
  return colors[status];
}

/**
 * Get task priority color
 */
export function getTaskPriorityColor(priority: MobileTaskCard['priority']): string {
  const colors: Record<MobileTaskCard['priority'], string> = {
    URGENT: '#DC2626',
    HIGH: '#F59E0B',
    NORMAL: '#3B82F6',
    LOW: '#6B7280',
  };
  return colors[priority];
}

/**
 * Check if device is online
 */
export function isOnline(): boolean {
  if (typeof navigator === 'undefined') return true;
  return (navigator as { onLine?: boolean }).onLine ?? true;
}

/**
 * Create default mobile app state
 */
export function createDefaultMobileAppState(): MobileAppState {
  return {
    currentBreakpoint: 'md',
    deviceType: 'tablet',
    orientation: 'PORTRAIT',
    navigation: {
      isMenuOpen: false,
      activeTab: 'home',
      activeRoute: '/',
      breadcrumbs: [],
    },
    offline: {
      networkStatus: 'ONLINE',
      queuedItems: [],
      pendingCount: 0,
      failedCount: 0,
    },
    pwa: {
      install: {
        isInstallable: false,
        isInstalled: false,
        isPromptDismissed: false,
      },
      update: {
        isUpdateAvailable: false,
        isUpdating: false,
      },
      serviceWorker: {
        isSupported: false,
        isRegistered: false,
        isActive: false,
        updateAvailable: false,
      },
    },
    accessibility: {
      reduceMotion: false,
      highContrast: false,
      largeText: false,
      screenReader: false,
    },
    bottomSheet: {
      isOpen: false,
      currentHeight: 0,
      config: DEFAULT_BOTTOM_SHEET_CONFIG,
    },
    pullToRefresh: {
      isRefreshing: false,
      pullDistance: 0,
      threshold: 80,
    },
  };
}

/**
 * Calculate grid columns for breakpoint
 */
export function getGridColumns(breakpoint: Breakpoint): number {
  return BREAKPOINTS[breakpoint].columns;
}

