   432→// ============================================================================
   433→// Helper Functions
   434→// ============================================================================
   435→
   436→/**
   437→ * Determine PM window status from percentage
   438→ */
   439→export function getPMWindowStatus(percentComplete: number): PMWindowStatus {
   440→  if (percentComplete >= 100) return 'OVERDUE';
   441→  if (percentComplete >= 95) return 'CRITICAL';
   442→  if (percentComplete >= 80) return 'APPROACHING';
   443→  return 'SAFE';
   444→}
   445→
   446→/**
   447→ * Calculate PM window data from train
   448→ */
   449→export function calculatePMWindow(
   450→  currentMileage: number,
   451→  targetMileage: number,
   452→  dailyAverage: number
   453→): PMWindowData {
   454→  const percentComplete = (currentMileage / targetMileage) * 100;
   455→  const kmRemaining = Math.max(0, targetMileage - currentMileage);
   456→  const daysRemaining = dailyAverage > 0 ? Math.ceil(kmRemaining / dailyAverage) : 999;
   457→
   458→  return {
   459→    level: 'PM1', // Will be set by caller
   460→    targetMileage,
   461→    currentMileage,
   462→    percentComplete: Math.min(100, percentComplete),
   463→    kmRemaining,
   464→    status: getPMWindowStatus(percentComplete),
   465→    daysRemaining,
   466→  };
   467→}
   468→
   469→/**
   470→ * Format mileage for display
   471→ */
   472→export function formatMileage(km: number): string {
   473→  if (km >= 1000) {
   474→    return `${(km / 1000).toFixed(1)}k km`;
   475→  }
   476→  return `${km.toLocaleString()} km`;
   477→}
   478→
   479→/**
   480→ * Format days remaining for display
   481→ */
   482→export function formatDaysRemaining(days: number): string {
   483→  if (days <= 0) return 'Overdue';
   484→  if (days === 1) return '1 day';
   485→  if (days < 7) return `${days} days`;
   486→  if (days < 30) return `${Math.ceil(days / 7)} weeks`;
   487→  return `${Math.ceil(days / 30)} months`;
   488→}
   489→
   490→/**
   491→ * Get filter chips from current filter state
   492→ */
   493→export function getFilterChips(filters: TrainGridFilters): FilterChip[] {
   494→  const chips: FilterChip[] = [];
   495→
   496→  if (filters.fleet !== 'ALL') {
   497→    chips.push({
   498→      id: 'fleet',
   499→      label: filters.fleet === 'KINKI_SHARYO' ? 'Kinki Sharyo' : 'Alstom',
   500→      filterKey: 'fleet',
   501→      value: filters.fleet,
   502→      removable: true,
   503→    });
   504→  }
   505→
   506→  if (filters.status !== 'ALL') {
   507→    chips.push({
   508→      id: 'status',
   509→      label: filters.status,
   510→      filterKey: 'status',
   511→      value: filters.status,
   512→      removable: true,
   513→    });
   514→  }
   515→
   516→  if (filters.pmDue !== 'ALL') {
   517→    const labels: Record<PMDueFilterOption, string> = {
   518→      ALL: 'All',
   519→      OVERDUE: 'Overdue',
   520→      THIS_WEEK: 'Due This Week',
   521→      THIS_MONTH: 'Due This Month',
   522→      NEXT_3_MONTHS: 'Due in 3 Months',
   523→    };
   524→    chips.push({
   525→      id: 'pmDue',
   526→      label: labels[filters.pmDue],
   527→      filterKey: 'pmDue',
   528→      value: filters.pmDue,
   529→      removable: true,
   530→    });
   531→  }
   532→
   533→  if (filters.search) {
   534→    chips.push({
   535→      id: 'search',
   536→      label: `"${filters.search}"`,
   537→      filterKey: 'search',
   538→      value: filters.search,
   539→      removable: true,
   540→    });
   541→  }
   542→
   543→  return chips;
   544→}
   545→
   546→/**
   547→ * Calculate summary counts from rows
   548→ */
   549→export function calculateSummaryCounts(rows: TrainGridRow[]): FleetSummaryCounts {
   550→  const summary: FleetSummaryCounts = {
   551→    total: rows.length,
   552→    byFitness: { FIT: 0, RESTRICTED: 0, UNFIT: 0 },
   553→    byStatus: { IN_SERVICE: 0, IN_MAINTENANCE: 0, OUT_OF_SERVICE: 0, RESERVED: 0 },
   554→    pmDueThisWeek: 0,
   555→    pmOverdue: 0,
   556→  };
   557→
   558→  for (const row of rows) {
   559→    summary.byFitness[row.fitnessStatus]++;
   560→    summary.byStatus[row.trainStatus]++;
   561→
   562→    if (row.pmWindow.status === 'OVERDUE') {
   563→      summary.pmOverdue++;
   564→    } else if (row.nextPM.daysRemaining <= 7) {
   565→      summary.pmDueThisWeek++;
   566→    }
   567→  }
   568→
   569→  return summary;
   570→}
   571→

